export const UFRJ_GERADO_2026_QUESTIONS: any[] = [
  { id: 'ufrj_gerado26_001', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 62 anos, tabagista, com dispneia progressiva e baqueteamento digital. Tomografia de tórax mostra padrão reticular subpleural com faveolamento em bases, sem outra causa identificada. Pode-se afirmar que o diagnóstico mais provável é:', options: ['fibrose pulmonar idiopática', 'sarcoidose pulmonar', 'pneumonia em organização criptogênica', 'histiocitose pulmonar de células de Langerhans'], correctIndex: 0, explanation: 'Faveolamento subpleural em bases com baqueteamento digital, sem outra causa identificada, é o padrão radiológico clássico da fibrose pulmonar idiopática. A sarcoidose costuma cursar com adenopatia hilar/mediastinal e infiltrado peribroncovascular, não faveolamento basal; a POC apresenta consolidações migratórias com boa resposta a corticoide, sem faveolamento; a histiocitose de Langerhans acomete tipicamente campos superiores e médios com cistos e nódulos, não faveolamento basal.' },
  { id: 'ufrj_gerado26_002', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 45 anos, com fadiga, prurido e elevação isolada de fosfatase alcalina, anticorpo antimitocôndria positivo. Pode-se afirmar que o diagnóstico mais provável é:', options: ['colangite biliar primária', 'colangite esclerosante primária', 'hepatite autoimune', 'doença de Wilson'], correctIndex: 0, explanation: 'Prurido, colestase isolada e anticorpo antimitocôndria positivo são marcadores clássicos da colangite biliar primária. A colangite esclerosante cursa com estenoses biliares à colangiorressonância e é antimitocôndria negativa; a hepatite autoimune cursa com transaminases elevadas e FAN/anti-músculo liso, não antimitocôndria; a doença de Wilson acomete pacientes jovens com ceruloplasmina baixa, sem relação com esse autoanticorpo.' },
  { id: 'ufrj_gerado26_003', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 55 anos, com dor lombar inflamatória de longa data, rigidez matinal prolongada e limitação da expansibilidade torácica, HLA-B27 positivo. Pode-se afirmar que o diagnóstico mais provável é:', options: ['espondilite anquilosante', 'hérnia de disco lombar', 'fibromialgia', 'osteoartrite lombar'], correctIndex: 0, explanation: 'Dor lombar inflamatória crônica, rigidez matinal prolongada, limitação torácica e HLA-B27 positivo são característicos da espondilite anquilosante. Hérnia de disco causa dor mecânica com irradiação radicular, não rigidez matinal prolongada; fibromialgia não cursa com limitação objetiva da expansibilidade torácica nem associação com HLA-B27; osteoartrite é doença degenerativa mecânica, sem rigidez matinal prolongada nem relação com esse marcador genético.' },
  { id: 'ufrj_gerado26_004', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 38 anos, com fenômeno de Raynaud grave, disfagia e espessamento cutâneo progressivo de mãos e face. Pode-se afirmar que o diagnóstico mais provável é:', options: ['esclerose sistêmica', 'dermatomiosite', 'lúpus eritematoso sistêmico', 'síndrome de Sjögren'], correctIndex: 0, explanation: 'Raynaud grave, disfagia por acometimento esofágico e espessamento cutâneo progressivo são a tríade clássica da esclerose sistêmica. Dermatomiosite cursa com fraqueza proximal e lesões de pele características (heliotropo, Gottron), não espessamento cutâneo difuso; lúpus não costuma causar espessamento cutâneo progressivo nem disfagia esofágica proeminente; Sjögren cursa com xerostomia/xeroftalmia, não com espessamento cutâneo.' },
  { id: 'ufrj_gerado26_005', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 60 anos, com poliúria, polidipsia e sódio sérico elevado, urina persistentemente diluída mesmo após restrição hídrica, com resposta à desmopressina. Pode-se afirmar que o diagnóstico mais provável é:', options: ['diabetes insípido central', 'diabetes insípido nefrogênico', 'SIADH', 'polidipsia psicogênica'], correctIndex: 0, explanation: 'A resposta à desmopressina (concentração da urina) confirma déficit de ADH endógeno, característico do diabetes insípido central, e não do tipo nefrogênico, no qual o rim não responde à desmopressina. SIADH cursa com hiponatremia e urina concentrada, achado oposto ao do caso; polidipsia psicogênica cursa com sódio normal ou baixo e sem resposta diagnóstica à desmopressina, pois o problema não é déficit de ADH.' },
  { id: 'ufrj_gerado26_006', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 50 anos, com hipertensão resistente e hipocalemia espontânea, atividade de renina plasmática suprimida e relação aldosterona/renina elevada. Pode-se afirmar que o diagnóstico mais provável é:', options: ['hiperaldosteronismo primário', 'feocromocitoma', 'síndrome de Cushing', 'estenose de artéria renal bilateral'], correctIndex: 0, explanation: 'Hipocalemia espontânea com renina suprimida e relação aldosterona/renina elevada é o padrão bioquímico clássico do hiperaldosteronismo primário. Feocromocitoma cursa com hipertensão paroxística e catecolaminas elevadas, sem esse padrão renina-aldosterona; síndrome de Cushing cursa com cortisol elevado e fácies típica; estenose de artéria renal ativa o sistema renina-angiotensina, cursando com renina alta, não suprimida.' },
  { id: 'ufrj_gerado26_007', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 70 anos, com anemia normocítica, insuficiência renal e proteinúria não nefrótica, eletroforese com pico monoclonal. Pode-se afirmar que a investigação mais apropriada é:', options: ['dosagem de cadeias leves livres séricas e mielograma', 'apenas reposição de ferro, sem outra investigação', 'biópsia renal isolada, sem avaliação hematológica', 'ultrassonografia renal isolada, sem outra investigação'], correctIndex: 0, explanation: 'Componente monoclonal associado a anemia e insuficiência renal exige investigação hematológica dirigida (cadeias leves livres e mielograma) para excluir mieloma múltiplo. Reposição de ferro isolada ignora o achado monoclonal preocupante; biópsia renal isolada não elucida a causa hematológica de base; ultrassonografia renal isolada não investiga a discrasia plasmocitária sugerida pela eletroforese.' },
  { id: 'ufrj_gerado26_008', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 30 anos, com febre recorrente, dor abdominal e artralgia desde a infância, história familiar mediterrânea, com amiloidose renal em familiar próximo. Pode-se afirmar que o diagnóstico mais provável é:', options: ['febre familiar do Mediterrâneo', 'lúpus eritematoso sistêmico', 'doença de Still do adulto', 'síndrome de Behçet'], correctIndex: 0, explanation: 'Crises febris recorrentes desde a infância, ascendência mediterrânea e amiloidose familiar são o quadro típico da febre familiar do Mediterrâneo. Lúpus não costuma iniciar na infância com esse padrão de crises autolimitadas nem tem essa associação étnica específica; doença de Still do adulto se inicia geralmente na vida adulta, não desde a infância; Behçet cursa com úlceras orais/genitais e uveíte, ausentes no caso.' },
  { id: 'ufrj_gerado26_009', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 55 anos, etilista, com ascite volumosa refratária a diurético em dose máxima. Pode-se afirmar que a conduta mais apropriada é:', options: ['paracentese terapêutica de alívio, com reposição de albumina se grande volume', 'aumento indefinido da dose de diurético', 'restrição hídrica isolada, sem paracentese', 'transplante hepático de urgência em todos os casos'], correctIndex: 0, explanation: 'Ascite refratária ao diurético em dose máxima é tratada com paracentese de alívio, repondo albumina quando o volume retirado é grande, para evitar disfunção circulatória pós-paracentese. Aumentar indefinidamente o diurético em ascite já refratária não traz benefício e aumenta o risco de lesão renal; restrição hídrica isolada não resolve a ascite volumosa sintomática; transplante hepático de urgência não é indicado apenas pela ascite refratária, sem avaliação mais ampla da função hepática.' },
  { id: 'ufrj_gerado26_010', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 40 anos, com xerostomia e xeroftalmia importantes, anti-Ro/SSA positivo, biópsia de glândula salivar com infiltrado linfocitário. Pode-se afirmar que o diagnóstico mais provável é:', options: ['síndrome de Sjögren', 'lúpus eritematoso sistêmico', 'esclerose sistêmica', 'sarcoidose'], correctIndex: 0, explanation: 'Xerostomia, xeroftalmia, biópsia salivar característica e anti-Ro/SSA positivo confirmam síndrome de Sjögren. Lúpus pode ter anti-Ro positivo mas não costuma ter esse infiltrado glandular como achado central; esclerose sistêmica cursa com espessamento cutâneo e Raynaud, não com essa biópsia salivar; sarcoidose causa infiltrado granulomatoso não caseoso, e não infiltrado linfocitário típico de Sjögren.' },
  { id: 'ufrj_gerado26_011', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 65 anos, com dor óssea, anemia, insuficiência renal e hipercalcemia, componente monoclonal na eletroforese. Pode-se afirmar que o diagnóstico mais provável é:', options: ['mieloma múltiplo', 'linfoma folicular', 'leucemia linfoide crônica', 'doença de Waldenström'], correctIndex: 0, explanation: 'A tétrade dor óssea, anemia, insuficiência renal e hipercalcemia associada a componente monoclonal é clássica do mieloma múltiplo. Linfoma folicular e leucemia linfoide crônica cursam com linfadenopatia/linfocitose e não com essa tétrade CRAB; a macroglobulinemia de Waldenström produz IgM e cursa com hiperviscosidade, não com esse padrão de lesão óssea e hipercalcemia.' },
  { id: 'ufrj_gerado26_012', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 28 anos, com artralgia, eritema malar poupando sulco nasolabial, fotossensibilidade e proteinúria, anti-DNA dupla-hélice positivo. Pode-se afirmar que o diagnóstico mais provável é:', options: ['lúpus eritematoso sistêmico', 'artrite reumatoide', 'dermatomiosite', 'esclerose sistêmica'], correctIndex: 0, explanation: 'Eritema malar poupando sulco nasolabial, fotossensibilidade, nefrite e anti-DNA dupla-hélice positivo são critérios clássicos de lúpus eritematoso sistêmico. Artrite reumatoide não cursa com eritema malar nem esse autoanticorpo; dermatomiosite tem lesões de pele diferentes (heliotropo, Gottron) e fraqueza muscular proeminente; esclerose sistêmica cursa com espessamento cutâneo, não com eritema malar fotossensível.' },
  { id: 'ufrj_gerado26_013', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 68 anos, com cefaleia temporal, claudicação mandibular e VHS muito elevado. Pode-se afirmar que a principal complicação a ser prevenida com tratamento imediato é:', options: ['cegueira por neuropatia óptica isquêmica', 'insuficiência renal aguda', 'meningite bacteriana', 'osteoporose grave'], correctIndex: 0, explanation: 'Cefaleia temporal e claudicação mandibular sugerem arterite de células gigantes; o corticoide deve ser iniciado prontamente para prevenir cegueira irreversível por neuropatia óptica isquêmica. Insuficiência renal aguda não é complicação típica dessa vasculite de grandes vasos cranianos; meningite bacteriana não tem relação fisiopatológica com o quadro; osteoporose é efeito adverso tardio do próprio tratamento com corticoide, não uma complicação da doença a ser prevenida com urgência.' },
  { id: 'ufrj_gerado26_014', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 55 anos, com fraqueza muscular proximal simétrica e pápulas violáceas sobre articulações interfalângicas. Pode-se afirmar que o diagnóstico mais provável é:', options: ['dermatomiosite', 'polimialgia reumática', 'miastenia gravis', 'esclerose lateral amiotrófica'], correctIndex: 0, explanation: 'Fraqueza proximal simétrica associada a pápulas de Gottron é achado patognomônico da dermatomiosite. Polimialgia reumática causa dor e rigidez em cinturas, não fraqueza muscular verdadeira nem pápulas de Gottron; miastenia gravis cursa com fraqueza flutuante e fatigável, sem lesões de pele; esclerose lateral amiotrófica cursa com sinais de neurônio motor superior e inferior, sem lesões cutâneas.' },
  { id: 'ufrj_gerado26_015', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 50 anos, com poliartrite simétrica de pequenas articulações das mãos, rigidez matinal prolongada, fator reumatoide positivo, erosões periarticulares. Pode-se afirmar que a classe medicamentosa a ser iniciada precocemente é:', options: ['droga modificadora do curso da doença (metotrexato)', 'apenas anti-inflamatório em longo prazo', 'opioide de forma contínua', 'corticoide isolado como única terapia permanente'], correctIndex: 0, explanation: 'O metotrexato, droga modificadora do curso da artrite reumatoide, deve ser iniciado precocemente para evitar dano articular progressivo. Anti-inflamatório isolado controla sintomas mas não impede a progressão erosiva; opioide contínuo não trata a doença de base e traz risco de dependência; corticoide isolado como terapia permanente expõe a efeitos adversos cumulativos sem modificar o curso da doença a longo prazo.' },
  { id: 'ufrj_gerado26_016', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 32 anos, com dor abdominal recorrente, diarreia com sangue e emagrecimento, colonoscopia com acometimento salteado transmural e fístulas perianais. Pode-se afirmar que o diagnóstico mais provável é:', options: ['doença de Crohn', 'retocolite ulcerativa', 'colite isquêmica', 'síndrome do intestino irritável'], correctIndex: 0, explanation: 'Acometimento salteado, transmural, com fístulas perianais, é característico da doença de Crohn, diferente do padrão contínuo e limitado à mucosa da retocolite ulcerativa, que também não costuma cursar com fístulas perianais. Colite isquêmica ocorre tipicamente em pacientes idosos com fatores de risco vascular e tem curso agudo; síndrome do intestino irritável não apresenta sangue, emagrecimento nem lesões estruturais à colonoscopia.' },
  { id: 'ufrj_gerado26_017', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 58 anos, com icterícia flutuante, dor em hipocôndrio direito e febre, colangiorressonância com estenoses e dilatações alternadas das vias biliares, associado a retocolite ulcerativa. Pode-se afirmar que o diagnóstico mais provável é:', options: ['colangite esclerosante primária', 'colangite biliar primária', 'coledocolitíase isolada', 'colangiocarcinoma isolado'], correctIndex: 0, explanation: 'O padrão de estenoses e dilatações alternadas ("colar de contas") associado a doença inflamatória intestinal é característico da colangite esclerosante primária. A colangite biliar primária cursa com anticorpo antimitocôndria positivo e não tem esse padrão colangiográfico; coledocolitíase isolada não explica o padrão difuso de estenoses nem a associação com retocolite; colangiocarcinoma isolado é uma complicação possível da colangite esclerosante, mas não a explicação inicial mais provável do quadro descrito.' },
  { id: 'ufrj_gerado26_018', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 60 anos, com dispneia progressiva, macroglossia e síndrome do túnel do carpo bilateral, ecocardiograma com padrão restritivo. Pode-se afirmar que o diagnóstico mais provável é:', options: ['amiloidose sistêmica', 'sarcoidose sistêmica', 'hemocromatose', 'doença de Fabry'], correctIndex: 0, explanation: 'Macroglossia, túnel do carpo bilateral e cardiomiopatia restritiva são achados característicos da amiloidose sistêmica. Sarcoidose cardíaca cursa mais com bloqueios de condução e arritmias que padrão restritivo típico associado a macroglossia; hemocromatose causa cardiomiopatia dilatada, não restritiva, e não causa macroglossia; a doença de Fabry cursa com hipertrofia ventricular e acroparestesias, sem essa tríade específica.' },
  { id: 'ufrj_gerado26_019', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 45 anos, com hipertensão paroxística, cefaleia e sudorese em crises, metanefrinas plasmáticas muito elevadas. Pode-se afirmar que o cuidado pré-operatório essencial antes da cirurgia é:', options: ['bloqueio alfa-adrenérgico antes do bloqueio beta', 'betabloqueador isolado antes de qualquer outra medida', 'corticoide em altas doses antes da cirurgia', 'espironolactona isolada, sem bloqueio alfa'], correctIndex: 0, explanation: 'No feocromocitoma, o bloqueio alfa deve preceder o beta, evitando vasoconstrição sem oposição e crise hipertensiva. Betabloqueador isolado antes do alfa-bloqueio é perigoso, pois permite ação alfa-adrenérgica sem oposição e pode precipitar crise hipertensiva grave; corticoide em altas doses não tem papel no preparo pré-operatório do feocromocitoma; espironolactona isolada não substitui o bloqueio alfa-adrenérgico específico necessário.' },
  { id: 'ufrj_gerado26_020', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 42 anos, com ganho de peso central, estrias violáceas, fácies em lua cheia, cortisol não suprimido pelo teste com dexametasona em dose baixa. Pode-se afirmar que o diagnóstico mais provável é:', options: ['síndrome de Cushing', 'hipotireoidismo grave', 'acromegalia', 'insuficiência adrenal crônica'], correctIndex: 0, explanation: 'Fácies em lua cheia, obesidade central, estrias violáceas e hipercortisolismo não suprimível confirmam síndrome de Cushing. Hipotireoidismo grave causa ganho de peso mas sem estrias violáceas nem hipercortisolismo; acromegalia cursa com aumento de extremidades e prognatismo, não com esse padrão hormonal; insuficiência adrenal cursa com cortisol baixo, exatamente o oposto do achado descrito.' },
  { id: 'ufrj_gerado26_021', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 55 anos, com fadiga, icterícia leve, anemia com reticulocitose, LDH elevado, haptoglobina baixa, Coombs direto positivo. Pode-se afirmar que o tratamento de primeira linha é:', options: ['corticoterapia', 'reposição de ferro oral', 'reposição de vitamina B12', 'transfusões crônicas isoladas'], correctIndex: 0, explanation: 'Hemólise com Coombs direto positivo confirma anemia hemolítica autoimune, tratada inicialmente com corticoide. Ferro oral não trata hemólise e pode ser inadequado sem deficiência confirmada; vitamina B12 trata anemia megaloblástica, não hemolítica autoimune; transfusões crônicas isoladas não tratam a causa autoimune de base e devem ser reservadas para casos graves refratários.' },
  { id: 'ufrj_gerado26_022', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 25 anos, com febre, exantema petequial e rigidez de nuca de início agudo, líquor com pleocitose neutrofílica importante. Pode-se afirmar que a conduta imediata, antes mesmo do resultado da cultura, é:', options: ['antibioticoterapia empírica imediata', 'aguardar resultado da cultura para iniciar antibiótico', 'apenas corticoide isolado, sem antibiótico', 'alta com anti-inflamatório e retorno ambulatorial'], correctIndex: 0, explanation: 'Suspeita de meningite bacteriana é emergência médica: antibioticoterapia empírica deve começar imediatamente após a coleta de exames, sem aguardar resultado de cultura. Aguardar a cultura atrasa o tratamento e aumenta mortalidade; corticoide isolado sem antibiótico não trata a infecção bacteriana subjacente; alta com anti-inflamatório é conduta inadequada e perigosa diante de sinais de meningite aguda.' },
  { id: 'ufrj_gerado26_023', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 40 anos, HIV positivo, CD4 de 90, com cefaleia progressiva e lesão com realce em anel em núcleos da base. Pode-se afirmar que o tratamento empírico inicial mais apropriado é:', options: ['sulfadiazina associada a pirimetamina', 'ceftriaxona isolada', 'anfotericina B isolada, sem investigação de imagem', 'quimioterapia isolada, sem tratamento empírico prévio'], correctIndex: 0, explanation: 'Lesão com realce em anel em núcleos da base em paciente com CD4 baixo é altamente sugestiva de neurotoxoplasmose, tratada empiricamente com sulfadiazina e pirimetamina. Ceftriaxona cobre bactérias, não o protozoário Toxoplasma gondii; anfotericina B é usada para infecções fúngicas (como criptococose), não para toxoplasmose; quimioterapia isolada seria voltada a linfoma primário do SNC, diagnóstico diferencial que só deve ser considerado após falha do tratamento empírico para toxoplasmose.' },
  { id: 'ufrj_gerado26_024', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 35 anos, com dor abdominal recorrente em crises, neuropatia periférica e urina que escurece à exposição à luz durante as crises. Pode-se afirmar que o diagnóstico mais provável é:', options: ['porfiria aguda intermitente', 'intoxicação por chumbo', 'síndrome de Guillain-Barré', 'porfiria cutânea tarda'], correctIndex: 0, explanation: 'Dor abdominal em crises, neuropatia periférica e urina que escurece à luz são clássicos da porfiria aguda intermitente. Intoxicação por chumbo causa dor abdominal e neuropatia mas não esse escurecimento urinário característico; Guillain-Barré causa neuropatia ascendente mas sem dor abdominal em crises nem alteração urinária; a porfiria cutânea tarda causa fotossensibilidade cutânea, não crises abdominais agudas com neuropatia.' },
  { id: 'ufrj_gerado26_025', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 62 anos, com dispneia paroxística noturna, ortopneia e BNP muito elevado, fração de ejeção de 30% ao ecocardiograma, já em uso de IECA, betabloqueador e antagonista mineralocorticoide otimizados. Pode-se afirmar que a próxima classe terapêutica a ser considerada é:', options: ['inibidor do cotransportador sódio-glicose tipo 2', 'bloqueador de canal de cálcio di-hidropiridínico', 'anti-inflamatório não esteroidal', 'antiarrítmico classe IC'], correctIndex: 0, explanation: 'Os inibidores de SGLT2 fazem parte da terapia quádrupla atual da insuficiência cardíaca com fração de ejeção reduzida, sendo o próximo passo terapêutico após otimização das demais classes. Bloqueador de canal de cálcio di-hidropiridínico não tem benefício comprovado de mortalidade nessa condição; anti-inflamatório não esteroidal é contraindicado por piorar retenção hidrossalina e função renal; antiarrítmico classe IC é contraindicado em cardiopatia estrutural pelo risco pró-arrítmico.' },
  { id: 'ufrj_gerado26_026', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 48 anos, com dor torácica pleurítica que piora ao deitar e melhora ao inclinar-se para frente, ECG com supradesnivelamento difuso do segmento ST côncavo, após quadro gripal recente. Pode-se afirmar que o tratamento mais apropriado é:', options: ['anti-inflamatório não esteroidal associado a colchicina', 'trombólise imediata', 'cirurgia de urgência', 'anticoagulação plena'], correctIndex: 0, explanation: 'Dor pleurítica postural com supra difuso côncavo após infecção viral é típica de pericardite aguda, tratada com anti-inflamatório associado a colchicina. Trombólise é tratamento de infarto com supra de ST, quadro distinto (dor não postural, supra localizado); cirurgia de urgência não tem indicação em pericardite não complicada; anticoagulação plena não é indicada e pode agravar eventual derrame pericárdico hemorrágico.' },
  { id: 'ufrj_gerado26_027', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 70 anos, com síncope aos esforços, sopro sistólico rude em foco aórtico, área valvar de 0,7 cm² ao ecocardiograma. Pode-se afirmar que a conduta definitiva é:', options: ['troca valvar aórtica, cirúrgica ou por via transcateter conforme risco', 'tratamento clínico exclusivo', 'apenas seguimento ecocardiográfico anual', 'betabloqueador em altas doses como única conduta'], correctIndex: 0, explanation: 'Estenose aórtica grave sintomática (síncope) tem indicação de troca valvar, seja cirúrgica ou transcateter conforme o risco do paciente. Tratamento clínico exclusivo não modifica a obstrução mecânica nem reduz o risco de morte súbita; seguimento isolado é conduta apropriada apenas para estenose assintomática, não para o caso sintomático descrito; betabloqueador em altas doses pode ser deletério na estenose aórtica grave por reduzir o débito cardíaco compensatório.' },
  { id: 'ufrj_gerado26_028', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 55 anos, com dispneia progressiva, estertores em velcro nas bases pulmonares, tomografia com padrão de faveolamento subpleural bibasal. Pode-se afirmar que o diagnóstico mais provável é:', options: ['fibrose pulmonar idiopática', 'DPOC enfisematoso', 'asma brônquica de início tardio', 'bronquiectasias difusas'], correctIndex: 0, explanation: 'Estertores em velcro com faveolamento subpleural bibasal são o padrão clássico da fibrose pulmonar idiopática. DPOC enfisematoso cursa com hiperinsuflação e redução do murmúrio vesicular, não estertores em velcro; asma de início tardio cursa com sibilos e reversibilidade ao broncodilatador, não faveolamento; bronquiectasias cursam com tosse produtiva crônica e imagem de dilatação brônquica, não faveolamento subpleural.' },
  { id: 'ufrj_gerado26_029', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 50 anos, com sonolência diurna excessiva, roncos altos e pausas respiratórias presenciadas pela esposa, obesidade importante. Pode-se afirmar que o exame confirmatório mais apropriado é:', options: ['polissonografia', 'espirometria com broncodilatador', 'radiografia de tórax isolada', 'apenas questionário clínico'], correctIndex: 0, explanation: 'A polissonografia é o exame padrão-ouro para confirmar a síndrome da apneia obstrutiva do sono. Espirometria avalia distúrbios ventilatórios obstrutivos/restritivos, não eventos respiratórios do sono; radiografia de tórax não detecta apneias; questionário clínico isolado apenas estratifica risco pré-teste, sem confirmar o diagnóstico.' },
  { id: 'ufrj_gerado26_030', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 30 anos, com diarreia crônica, distensão abdominal e anemia ferropriva, sorologia positiva para antitransglutaminase. Pode-se afirmar que o tratamento indicado é:', options: ['dieta isenta de glúten', 'corticoide isolado', 'antibiótico de amplo espectro', 'dieta isenta de lactose'], correctIndex: 0, explanation: 'Anticorpos antitransglutaminase positivos confirmam doença celíaca, tratada com dieta isenta de glúten por toda a vida. Corticoide isolado não trata a causa autoimune desencadeada pelo glúten; antibiótico de amplo espectro não tem papel nessa enteropatia não infecciosa; dieta isenta de lactose trataria intolerância à lactose, condição distinta que não explica a sorologia positiva.' },
  { id: 'ufrj_gerado26_031', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 45 anos, com dor abdominal em faixa irradiada para o dorso, náuseas e vômitos após ingestão alcoólica importante, lipase 6 vezes o valor de referência. Pode-se afirmar que a conduta inicial mais apropriada é:', options: ['hidratação venosa vigorosa, analgesia e jejum inicial conforme tolerância', 'antibioticoterapia profilática de rotina', 'cirurgia pancreática imediata', 'CPRE de urgência independente de obstrução biliar'], correctIndex: 0, explanation: 'O tratamento inicial da pancreatite aguda é hidratação venosa vigorosa, analgesia adequada e dieta conforme tolerância, sem antibiótico profilático de rotina. Antibioticoterapia profilática não é recomendada na ausência de infecção confirmada; cirurgia pancreática imediata não é indicada na fase inicial da pancreatite aguda não complicada; CPRE de urgência só é indicada quando há obstrução biliar concomitante, ausente nesse caso de etiologia alcoólica.' },
  { id: 'ufrj_gerado26_032', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 60 anos, com dor lombar recorrente e cálculos renais bilaterais, hipercalciúria e nefrocalcinose, cálcio e PTH séricos elevados. Pode-se afirmar que a conduta definitiva mais apropriada é:', options: ['paratireoidectomia', 'restrição hídrica isolada', 'nefrectomia bilateral', 'apenas analgesia para as crises de cólica'], correctIndex: 0, explanation: 'Hipercalcemia com PTH elevado confirma hiperparatireoidismo primário; a paratireoidectomia é o tratamento definitivo em pacientes com critérios de tratamento cirúrgico. Restrição hídrica isolada não corrige a causa hormonal da hipercalciúria; nefrectomia bilateral é conduta desproporcional e não trata a origem paratireoidiana do distúrbio; analgesia isolada apenas trata sintomas das crises, sem impedir a progressão da nefrocalcinose.' },
  { id: 'ufrj_gerado26_033', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 68 anos, com paraparesia progressiva, nível sensitivo definido no tronco e disfunção esfincteriana de início subagudo. Pode-se afirmar que a conduta de investigação mais urgente é:', options: ['ressonância magnética de coluna de urgência para excluir compressão medular', 'eletroneuromiografia como primeiro exame', 'punção lombar isolada, sem imagem prévia', 'apenas observação clínica por 48 horas'], correctIndex: 0, explanation: 'Nível sensitivo definido e disfunção esfincteriana subaguda são sinais de alarme para compressão medular, exigindo ressonância de urgência antes de qualquer outro exame. Eletroneuromiografia avalia nervo periférico, não é o exame inicial diante de suspeita de lesão medular compressiva; punção lombar sem imagem prévia é perigosa, pois pode precipitar herniação em massa compressiva; observação por 48 horas atrasa perigosamente o diagnóstico de uma emergência neurológica potencialmente reversível.' },
  { id: 'ufrj_gerado26_034', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 27 anos, com episódios recorrentes de perda visual unilateral, parestesias e fraqueza em membros, lesões desmielinizantes disseminadas no espaço e no tempo à ressonância. Pode-se afirmar que o diagnóstico mais provável é:', options: ['esclerose múltipla', 'neuromielite óptica isolada', 'acidente vascular cerebral de repetição', 'miastenia gravis'], correctIndex: 0, explanation: 'Lesões desmielinizantes disseminadas no espaço e no tempo são o critério diagnóstico central da esclerose múltipla. A neuromielite óptica tipicamente cursa com lesões extensas de medula e nervo óptico com padrão diferente e anticorpo anti-aquaporina-4 positivo; AVC de repetição ocorreria em paciente com fatores de risco vascular e lesões vasculares, não desmielinizantes; miastenia gravis é doença da junção neuromuscular, sem lesões de substância branca à ressonância.' },
  { id: 'ufrj_gerado26_035', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 58 anos, com fraqueza muscular com fadiga que piora ao longo do dia, ptose e diplopia flutuantes, melhora da ptose ao teste do gelo. Pode-se afirmar que o diagnóstico mais provável é:', options: ['miastenia gravis', 'esclerose lateral amiotrófica', 'síndrome de Guillain-Barré', 'distrofia muscular de Duchenne'], correctIndex: 0, explanation: 'Fraqueza flutuante que piora ao longo do dia, com melhora da ptose ao teste do gelo, é característica da miastenia gravis. Esclerose lateral amiotrófica cursa com fraqueza progressiva não flutuante e sinais de neurônio motor superior; Guillain-Barré cursa com fraqueza ascendente aguda e arreflexia, não flutuação diária; distrofia de Duchenne acomete meninos na infância, com fraqueza progressiva não flutuante.' },
  { id: 'ufrj_gerado26_036', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 33 anos, com fraqueza ascendente progressiva após infecção gastrointestinal, arreflexia. Pode-se afirmar que a conduta mais apropriada é:', options: ['imunoglobulina intravenosa ou plasmaférese, com monitorização respiratória', 'piridostigmina isolada', 'corticoide isolado', 'apenas observação, sem tratamento específico'], correctIndex: 0, explanation: 'Fraqueza ascendente com arreflexia após infecção prévia é a síndrome de Guillain-Barré, tratada com imunoglobulina ou plasmaférese e monitorização respiratória rigorosa. Piridostigmina é tratamento de miastenia gravis, não de Guillain-Barré; corticoide isolado não tem eficácia comprovada nessa condição; observação isolada é perigosa pelo risco de insuficiência respiratória progressiva sem tratamento específico.' },
  { id: 'ufrj_gerado26_037', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 45 anos, com cefaleia pulsátil unilateral recorrente precedida de escotomas cintilantes, náusea e fotofobia. Pode-se afirmar que o tratamento abortivo de escolha na crise moderada a grave é:', options: ['triptano', 'carbamazepina', 'oxigênio a alto fluxo isolado', 'analgésico comum isolado'], correctIndex: 0, explanation: 'O triptano é o tratamento abortivo de escolha na crise moderada a grave de enxaqueca com aura. Carbamazepina é usada em profilaxia de neuralgias, não como abortivo de enxaqueca; oxigênio a alto fluxo é o tratamento abortivo específico da cefaleia em salvas, não da enxaqueca; analgésico comum isolado é insuficiente para crises moderadas a graves de enxaqueca.' },
  { id: 'ufrj_gerado26_038', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 65 anos, com declínio cognitivo progressivo, alucinações visuais bem formadas e parkinsonismo, flutuação importante da atenção. Pode-se afirmar que a classe medicamentosa a ser evitada é:', options: ['antipsicóticos típicos', 'anticolinesterásicos', 'anticoagulantes', 'levodopa'], correctIndex: 0, explanation: 'Na demência com corpos de Lewy, antipsicóticos típicos devem ser evitados pelo alto risco de reações extrapiramidais graves e hipersensibilidade neuroléptica. Anticolinesterásicos são úteis para o componente cognitivo e alucinatório dessa demência; anticoagulantes não têm relação com essa hipersensibilidade específica; levodopa pode ser usada com cautela para o parkinsonismo, sem o mesmo risco de hipersensibilidade que os antipsicóticos típicos.' },
  { id: 'ufrj_gerado26_039', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 50 anos, com dor abdominal difusa e distensão, distensão colônica importante à radiografia, sem obstrução mecânica evidente. Pode-se afirmar que a conduta inicial mais apropriada é:', options: ['correção de distúrbios metabólicos e considerar neostigmina se refratário', 'colectomia total de urgência em todos os casos', 'apenas jejum prolongado, sem qualquer medicação específica', 'antibioticoterapia isolada, sem descompressão do cólon'], correctIndex: 0, explanation: 'A pseudo-obstrução colônica aguda (síndrome de Ogilvie) é inicialmente tratada com correção metabólica e neostigmina em casos refratários, reservando cirurgia para complicações. Colectomia total de urgência em todos os casos é desproporcional para um quadro inicialmente funcional e reversível; jejum isolado sem correção metabólica não trata a causa da atonia colônica; antibioticoterapia isolada não resolve a distensão colônica sem medidas de descompressão.' },
  { id: 'ufrj_gerado26_040', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 55 anos, com fadiga, sangramentos gengivais e petéquias, pancitopenia com blastos circulantes, mielograma com mais de 20% de blastos mieloides. Pode-se afirmar que é necessária atenção especial ao subtipo:', options: ['promielocítico, pelo risco de coagulopatia grave', 'linfocítico crônico, sem urgência hemorrágica', 'mielofibrótico, sem indicação de esplenectomia de urgência', 'não Hodgkin, sem relação com CIVD'], correctIndex: 0, explanation: 'A leucemia promielocítica aguda cursa com risco elevado de coagulação intravascular disseminada, exigindo reconhecimento e manejo hemostático precoce. Leucemia linfocítica crônica é doença indolente sem essa urgência hemorrágica típica; leucemia mielofibrótica não se define por blastos agudos nem tem essa mesma urgência coagulopática; linfoma não Hodgkin não é o diagnóstico compatível com mais de 20% de blastos mieloides no mielograma.' },
  { id: 'ufrj_gerado26_041', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 60 anos, com linfonodomegalia cervical indolor, sudorese noturna e febre, biópsia com células de Reed-Sternberg. Pode-se afirmar que a próxima etapa antes de definir o tratamento é:', options: ['estadiamento com tomografia e/ou PET-CT', 'quimioterapia imediata sem qualquer estadiamento', 'radioterapia isolada sem confirmação de extensão da doença', 'apenas observação clínica sem tratamento'], correctIndex: 0, explanation: 'Após confirmação histológica de linfoma de Hodgkin, o estadiamento por imagem é essencial para planejar o tratamento adequado. Quimioterapia imediata sem estadiamento impede a escolha correta do esquema e da duração do tratamento; radioterapia isolada sem confirmar a extensão da doença pode subtratar doença mais avançada; observação isolada é inadequada diante de um linfoma confirmado, que exige tratamento.' },
  { id: 'ufrj_gerado26_042', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 45 anos, com sinusite crônica, hemoptise e insuficiência renal rapidamente progressiva, ANCA-c positivo. Pode-se afirmar que o diagnóstico mais provável é:', options: ['granulomatose com poliangiite', 'lúpus eritematoso sistêmico', 'síndrome de Goodpasture isolada', 'poliarterite nodosa clássica'], correctIndex: 0, explanation: 'Acometimento de vias aéreas superiores, pulmão e rim com ANCA-c/anti-PR3 positivo é típico da granulomatose com poliangiite. Lúpus não costuma cursar com sinusite crônica nem ANCA-c positivo; a síndrome de Goodpasture isolada é definida por anticorpo anti-membrana basal glomerular, não ANCA; a poliarterite nodosa clássica não acomete glomérulos nem tem associação com ANCA.' },
  { id: 'ufrj_gerado26_043', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 55 anos, com dor torácica súbita intensa irradiando para o dorso, descrita como "rasgando", diferença de pressão arterial maior que 20 mmHg entre os braços. Pode-se afirmar que a conduta imediata é:', options: ['controle rigoroso da frequência cardíaca e pressão arterial, com angiotomografia de urgência', 'trombólise imediata', 'anti-inflamatório isolado', 'anticoagulação plena imediata sem outra investigação'], correctIndex: 0, explanation: 'Suspeita de dissecção de aorta exige controle imediato de frequência e pressão (betabloqueador) antes da confirmação por angiotomografia. Trombólise é contraindicada na suspeita de dissecção, pois pode agravar sangramento e a própria dissecção; anti-inflamatório isolado não trata a emergência vascular; anticoagulação plena sem investigação prévia é perigosa e contraindicada nesse contexto.' },
  { id: 'ufrj_gerado26_044', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 50 anos, com fadiga, ganho de peso, constipação e intolerância ao frio, TSH elevado, anti-TPO positivo. Pode-se afirmar que o diagnóstico e a conduta são:', options: ['tireoidite de Hashimoto; reposição de levotiroxina', 'doença de Graves; tionamida antitireoidiana', 'tireoidite subaguda; anti-inflamatório', 'bócio multinodular tóxico; iodo radioativo'], correctIndex: 0, explanation: 'TSH elevado com anti-TPO positivo confirma hipotireoidismo primário autoimune (Hashimoto), tratado com levotiroxina. Doença de Graves cursa com hipertireoidismo (TSH baixo), quadro oposto; tireoidite subaguda cursa com dor cervical e fase inicial de hipertireoidismo, diferente do quadro descrito; bócio multinodular tóxico também cursa com hipertireoidismo, não hipotireoidismo.' },
  { id: 'ufrj_gerado26_045', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 65 anos, com doença renal crônica avançada, náuseas persistentes, prurido e derrame pericárdico leve. Pode-se afirmar que a conduta definitiva é:', options: ['início de terapia renal substitutiva', 'aumento da dose de diurético de alça isoladamente', 'restrição proteica rigorosa como tratamento definitivo', 'uso isolado de quelante de fósforo'], correctIndex: 0, explanation: 'Uremia sintomática com complicação (pericardite) em DRC avançada é indicação clássica de início de diálise. Aumento isolado do diurético não remove toxinas urêmicas nem resolve a pericardite; restrição proteica rigorosa isolada não é tratamento definitivo diante de uremia sintomática grave; quelante de fósforo isolado trata apenas um distúrbio metabólico associado, não a uremia sintomática como um todo.' },
  { id: 'ufrj_gerado26_046', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 35 anos, com pancitopenia leve, esplenomegalia, hepatomegalia e dor óssea, mielograma com células de aspecto de "papel amassado". Pode-se afirmar que o diagnóstico mais provável é:', options: ['doença de Gaucher', 'leucemia linfoblástica aguda isolada', 'talassemia maior', 'histiocitose de células de Langerhans'], correctIndex: 0, explanation: 'Células com aspecto de "papel amassado" no mielograma, associadas a organomegalia, são características da doença de Gaucher. Leucemia linfoblástica aguda cursa com blastos linfoides, não com essas células de depósito lipídico; talassemia maior cursa com hemólise crônica e alterações eritrocitárias típicas, não com essas células; histiocitose de Langerhans tem achado histológico e clínico distinto, sem esse padrão celular específico.' },
  { id: 'ufrj_gerado26_047', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 40 anos, com hipertensão arterial e hipocalemia, sem uso de diurético, atividade de renina plasmática suprimida bilateralmente confirmada por cateterismo de veias adrenais. Pode-se afirmar que a conduta mais apropriada é:', options: ['tratamento clínico com antagonista da aldosterona, dado o acometimento bilateral', 'adrenalectomia unilateral, independente da lateralização', 'observação isolada, sem qualquer tratamento', 'radioterapia da adrenal'], correctIndex: 0, explanation: 'Hiperaldosteronismo primário bilateral (confirmado por cateterismo de veias adrenais) é tratado clinicamente com antagonista da aldosterona, reservando cirurgia para doença unilateral lateralizada. Adrenalectomia unilateral não corrigiria a hipersecreção bilateral confirmada; observação isolada não trata a hipertensão nem a hipocalemia; radioterapia da adrenal não é modalidade terapêutica utilizada nessa condição.' },
  { id: 'ufrj_gerado26_048', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 55 anos, com edema de face e membros superiores, turgência jugular fixa, circulação colateral em tórax, dispneia progressiva, massa mediastinal ao raio-x. Pode-se afirmar que o diagnóstico sindrômico mais provável é:', options: ['síndrome da veia cava superior', 'insuficiência cardíaca direita isolada', 'tamponamento cardíaco', 'trombose venosa profunda de membro superior isolada'], correctIndex: 0, explanation: 'Edema de face/membros superiores, turgência jugular fixa e circulação colateral com massa mediastinal são clássicos da síndrome da veia cava superior. Insuficiência cardíaca direita isolada não explicaria a massa mediastinal nem o padrão de edema restrito à parte superior do corpo; tamponamento cardíaco cursa com hipotensão e pulso paradoxal, não esse padrão de edema/colaterais; TVP de membro superior isolada não explicaria o edema facial nem a massa mediastinal.' },
  { id: 'ufrj_gerado26_049', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 48 anos, com febre prolongada, sopro cardíaco novo e fenômenos embólicos periféricos, hemoculturas positivas para Streptococcus viridans. Pode-se afirmar que o conjunto de critérios que confirma o diagnóstico é:', options: ['critérios de Duke modificados', 'critérios de Jones', 'critérios de Framingham', 'critérios de Light'], correctIndex: 0, explanation: 'Os critérios de Duke modificados combinam achados clínicos, ecocardiográficos e microbiológicos para o diagnóstico de endocardite infecciosa. Os critérios de Jones são usados para febre reumática, não endocardite; os critérios de Framingham avaliam risco cardiovascular geral, não endocardite; os critérios de Light classificam derrames pleurais, sem relação com esse diagnóstico.' },
  { id: 'ufrj_gerado26_050', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 60 anos, com fraqueza muscular proximal, disfagia e elevação importante de enzimas musculares, sem lesões cutâneas. Pode-se afirmar que o diagnóstico mais provável é:', options: ['polimiosite', 'dermatomiosite', 'miastenia gravis', 'polimialgia reumática'], correctIndex: 0, explanation: 'Fraqueza proximal com enzimas musculares elevadas e ausência de lesões cutâneas caracterizam a polimiosite, diferente da dermatomiosite (que tem achados de pele como heliotropo e pápulas de Gottron). Miastenia gravis cursa com fraqueza flutuante e enzimas musculares normais; polimialgia reumática causa dor e rigidez, sem elevação relevante de enzimas musculares nem fraqueza verdadeira.' },
  { id: 'ufrj_gerado26_051', banca: 'UFRJ', cycle: 'Ciclo Cirurgico', subject: 'Cirurgia Geral', text: 'Homem, 55 anos, com massa abdominal pulsátil e indolor, aneurisma de aorta abdominal infrarrenal de 5,8 cm ao ultrassom, assintomático. Pode-se afirmar que a conduta mais apropriada é:', options: ['correção cirúrgica eletiva (aberta ou endovascular)', 'acompanhamento seriado sem intervenção', 'anticoagulação plena isolada', 'embolização isolada sem exclusão do saco aneurismático'], correctIndex: 0, explanation: 'Aneurisma de aorta abdominal acima de 5,5 cm tem indicação de correção eletiva pelo risco progressivo de rotura. Acompanhamento seriado sem intervenção é conduta apropriada apenas para aneurismas menores, abaixo do limiar cirúrgico; anticoagulação plena isolada não trata o risco de rotura nem é indicada nessa condição; embolização isolada sem exclusão completa do saco aneurismático não elimina o risco de rotura.' },
  { id: 'ufrj_gerado26_052', banca: 'UFRJ', cycle: 'Ciclo Cirurgico', subject: 'Cirurgia Geral', text: 'Mulher, 50 anos, com dor em hipocôndrio direito após refeição gordurosa, febre, sinal de Murphy positivo, espessamento vesicular ao ultrassom. Pode-se afirmar que a conduta preconizada é:', options: ['colecistectomia videolaparoscópica precoce', 'apenas antibioticoterapia prolongada', 'colecistectomia aberta obrigatória', 'CPRE de urgência como tratamento definitivo'], correctIndex: 0, explanation: 'As diretrizes de Tóquio recomendam colecistectomia videolaparoscópica precoce para colecistite aguda em pacientes com boas condições clínicas. Antibioticoterapia prolongada isolada não remove o foco infeccioso vesicular; colecistectomia aberta obrigatória não é necessária, pois a via laparoscópica é preferida quando factível; CPRE de urgência é indicada para obstrução de via biliar principal, não como tratamento definitivo da colecistite em si.' },
  { id: 'ufrj_gerado26_053', banca: 'UFRJ', cycle: 'Ciclo Cirurgico', subject: 'Cirurgia Geral', text: 'Homem, 68 anos, com dor abdominal súbita intensa, abdome em tábua, pneumoperitônio à radiografia. Pode-se afirmar que a conduta imediata é:', options: ['laparotomia exploradora de urgência', 'tratamento clínico exclusivo', 'colonoscopia diagnóstica antes de decidir', 'alta com retorno em 48 horas'], correctIndex: 0, explanation: 'Pneumoperitônio com abdome em tábua indica perfuração de víscera oca, exigindo laparotomia exploradora imediata. Tratamento clínico exclusivo não resolve a perfuração nem a peritonite associada; colonoscopia diagnóstica é contraindicada e perigosa diante de perfuração já confirmada; alta com retorno tardio é conduta inadequada e arriscada diante de um abdome agudo perfurativo.' },
  { id: 'ufrj_gerado26_054', banca: 'UFRJ', cycle: 'Ciclo Cirurgico', subject: 'Cirurgia Geral', text: 'Mulher, 60 anos, com perda de peso, saciedade precoce e anemia ferropriva, endoscopia com lesão ulcerada infiltrativa em antro gástrico, biópsia confirma adenocarcinoma. Pode-se afirmar que a próxima etapa antes da cirurgia é:', options: ['estadiamento com tomografia de tórax e abdome', 'gastrectomia total imediata sem qualquer estadiamento', 'quimioterapia isolada sem avaliação cirúrgica', 'apenas seguimento clínico sem intervenção'], correctIndex: 0, explanation: 'Após confirmação histológica de câncer gástrico, o estadiamento é essencial para definir a estratégia cirúrgica ou neoadjuvante. Gastrectomia total imediata sem estadiamento arrisca uma cirurgia inadequada diante de doença metastática não detectada; quimioterapia isolada sem avaliação cirúrgica ignora a possibilidade de doença ressecável; seguimento clínico sem intervenção é inadequado diante de câncer confirmado.' },
  { id: 'ufrj_gerado26_055', banca: 'UFRJ', cycle: 'Ciclo Cirurgico', subject: 'Cirurgia Geral', text: 'Homem, 30 anos, vítima de acidente automobilístico, estável hemodinamicamente, laceração hepática grau III sem sangramento ativo à tomografia. Pode-se afirmar que a conduta mais apropriada é:', options: ['conduta não operatória com monitorização em UTI', 'laparotomia exploradora imediata em todos os casos', 'embolização obrigatória independente do quadro', 'alta hospitalar precoce sem monitorização'], correctIndex: 0, explanation: 'Paciente estável com lesão hepática sem sangramento ativo pode ser tratado de forma não operatória, com monitorização rigorosa. Laparotomia imediata em todos os casos submeteria pacientes estáveis a risco cirúrgico desnecessário; embolização obrigatória não é indicada na ausência de sangramento ativo identificado; alta precoce sem monitorização é perigosa, pois a lesão hepática exige observação rigorosa mesmo sem sangramento ativo inicial.' },
  { id: 'ufrj_gerado26_056', banca: 'UFRJ', cycle: 'Ciclo Cirurgico', subject: 'Cirurgia Geral', text: 'Mulher, 45 anos, com massa mamária endurecida aderida a planos profundos, retração cutânea. Pode-se afirmar que a conduta diagnóstica inicial mais apropriada é:', options: ['mamografia e biópsia da lesão', 'mastectomia imediata sem biópsia', 'apenas seguimento clínico em 6 meses', 'quimioterapia empírica sem biópsia'], correctIndex: 0, explanation: 'Massa mamária suspeita exige mamografia e biópsia para confirmação histológica antes de qualquer decisão terapêutica. Mastectomia imediata sem biópsia submeteria a paciente a cirurgia mutiladora sem diagnóstico confirmado; seguimento em 6 meses atrasa perigosamente o diagnóstico de uma lesão com sinais clínicos suspeitos; quimioterapia empírica sem biópsia trataria uma doença ainda não confirmada histologicamente.' },
  { id: 'ufrj_gerado26_057', banca: 'UFRJ', cycle: 'Ciclo Cirurgico', subject: 'Cirurgia Geral', text: 'Homem, 60 anos, com alteração do hábito intestinal e sangue oculto positivo, colonoscopia com lesão vegetante em sigmoide, biópsia confirma adenocarcinoma. Pode-se afirmar que a próxima etapa é:', options: ['estadiamento com tomografia de tórax, abdome e pelve e dosagem de CEA', 'colectomia imediata sem qualquer estadiamento', 'quimioterapia isolada sem avaliação cirúrgica prévia', 'apenas observação clínica sem qualquer conduta adicional'], correctIndex: 0, explanation: 'O estadiamento correto do câncer colorretal, incluindo CEA basal, é essencial antes de definir a estratégia cirúrgica. Colectomia imediata sem estadiamento pode resultar em cirurgia inadequada diante de doença metastática oculta; quimioterapia isolada sem avaliação cirúrgica ignora a doença potencialmente ressecável; observação clínica isolada é inaceitável diante de câncer colorretal já confirmado.' },
  { id: 'ufrj_gerado26_058', banca: 'UFRJ', cycle: 'Ciclo Pediatrico', subject: 'Pediatria', text: 'Lactente, 4 meses, com vômitos em jato pós-prandiais, oliva palpável em epigástrio, alcalose metabólica hipoclorêmica. Pode-se afirmar que a conduta antes da cirurgia é:', options: ['correção do distúrbio hidroeletrolítico', 'cirurgia imediata sem correção prévia', 'antibioticoterapia isolada', 'apenas dieta espessada, sem cirurgia'], correctIndex: 0, explanation: 'Na estenose hipertrófica do piloro, o distúrbio hidroeletrolítico deve ser corrigido antes da piloromiotomia definitiva. Cirurgia imediata sem correção prévia aumenta o risco anestésico-metabólico; antibioticoterapia isolada não trata a obstrução mecânica pilórica; dieta espessada isolada não resolve a obstrução anatômica que exige correção cirúrgica.' },
  { id: 'ufrj_gerado26_059', banca: 'UFRJ', cycle: 'Ciclo Pediatrico', subject: 'Pediatria', text: 'Criança, 3 anos, com febre há 6 dias, língua em framboesa, edema de mãos e pés, exantema polimorfo. Pode-se afirmar que a principal complicação a ser monitorada é:', options: ['aneurisma de artérias coronárias', 'insuficiência renal crônica', 'meningite bacteriana', 'osteomielite'], correctIndex: 0, explanation: 'Esse quadro é típico da doença de Kawasaki, cuja principal complicação a prevenir com imunoglobulina é o aneurisma coronariano. Insuficiência renal crônica não é a complicação característica dessa vasculite; meningite bacteriana e osteomielite não têm relação fisiopatológica direta com a doença de Kawasaki.' },
  { id: 'ufrj_gerado26_060', banca: 'UFRJ', cycle: 'Ciclo Pediatrico', subject: 'Pediatria', text: 'Lactente, 10 meses, com choro intenso intermitente, letargia, fezes em "geleia de framboesa", massa palpável em hipocôndrio direito. Pode-se afirmar que a conduta inicial é:', options: ['redução por enema hidrostático guiado por imagem', 'apendicectomia imediata', 'cintilografia como tratamento definitivo', 'apenas hidratação oral'], correctIndex: 0, explanation: 'Esse quadro clássico de invaginação intestinal é inicialmente tratado por redução não cirúrgica com enema guiado por imagem, na ausência de sinais de perfuração. Apendicectomia imediata não trata a invaginação intestinal, condição distinta; cintilografia não é modalidade terapêutica para essa condição; hidratação oral isolada não resolve a obstrução mecânica intestinal.' },
  { id: 'ufrj_gerado26_061', banca: 'UFRJ', cycle: 'Ciclo Pediatrico', subject: 'Pediatria', text: 'Criança, 6 anos, com enurese noturna isolada e exame físico normal. Pode-se afirmar que a conduta inicial é:', options: ['orientação comportamental e reasseguramento', 'desmopressina imediata sem orientação comportamental prévia', 'investigação urológica invasiva imediata', 'restrição hídrica extrema durante todo o dia'], correctIndex: 0, explanation: 'Enurese isolada sem sinais de alarme é tratada inicialmente com orientação comportamental, reservando medicação para casos persistentes. Desmopressina imediata sem tentativa comportamental prévia pula uma etapa terapêutica de primeira linha; investigação urológica invasiva não é indicada na ausência de sinais de alarme; restrição hídrica extrema durante todo o dia é inadequada e pode causar desidratação.' },
  { id: 'ufrj_gerado26_062', banca: 'UFRJ', cycle: 'Ciclo Pediatrico', subject: 'Pediatria', text: 'Recém-nascido com icterícia nas primeiras 24 horas de vida, Coombs direto positivo, mãe Rh negativo sensibilizada. Pode-se afirmar que a conduta mais provável a ser necessária é:', options: ['fototerapia intensiva e possível exsanguineotransfusão conforme evolução', 'apenas observação clínica, sem qualquer tratamento', 'suspensão do aleitamento materno como única conduta', 'antibioticoterapia empírica isolada'], correctIndex: 0, explanation: 'Icterícia precoce por doença hemolítica perinatal exige fototerapia intensiva, com exsanguineotransfusão reservada a casos graves. Observação isolada é perigosa diante de icterícia precoce por hemólise, que pode evoluir rapidamente; suspender o aleitamento materno não trata a causa hemolítica da icterícia; antibioticoterapia empírica não trata uma icterícia de causa hemolítica confirmada.' },
  { id: 'ufrj_gerado26_063', banca: 'UFRJ', cycle: 'Ciclo Ginecologico', subject: 'Ginecologia e Obstetrícia', text: 'Gestante, 34 semanas, com PA 165/105 mmHg, cefaleia e escotomas visuais. Pode-se afirmar que a conduta imediata é:', options: ['sulfato de magnésio e avaliação para resolução da gestação', 'repouso domiciliar, sem qualquer medicação', 'anti-hipertensivo oral ambulatorial isolado', 'aguardar 48 horas antes de qualquer conduta'], correctIndex: 0, explanation: 'PA muito elevada com sintomas premonitórios caracteriza pré-eclâmpsia grave, exigindo sulfato de magnésio e avaliação para resolução da gestação. Repouso domiciliar sem medicação não trata a gravidade do quadro nem previne eclâmpsia; anti-hipertensivo oral ambulatorial isolado é insuficiente diante de sinais premonitórios de eclâmpsia; aguardar 48 horas atrasa perigosamente uma emergência obstétrica.' },
  { id: 'ufrj_gerado26_064', banca: 'UFRJ', cycle: 'Ciclo Ginecologico', subject: 'Ginecologia e Obstetrícia', text: 'Mulher, 30 anos, com dismenorreia progressiva e infertilidade, ressonância com endometrioma ovariano. Pode-se afirmar que o diagnóstico é:', options: ['endometriose', 'miomatose uterina', 'doença inflamatória pélvica', 'câncer de ovário'], correctIndex: 0, explanation: 'Dismenorreia progressiva, infertilidade e endometrioma ovariano são compatíveis com endometriose. Miomatose uterina cursa com sangramento aumentado e miomas uterinos, não endometrioma ovariano; doença inflamatória pélvica cursa com quadro infeccioso agudo, não com endometrioma crônico; câncer de ovário teria características de imagem distintas e mais preocupantes do que um endometrioma típico.' },
  { id: 'ufrj_gerado26_065', banca: 'UFRJ', cycle: 'Ciclo Ginecologico', subject: 'Ginecologia e Obstetrícia', text: 'Puérpera imediata com sangramento importante e útero hipotônico à palpação. Pode-se afirmar que a primeira conduta é:', options: ['massagem uterina e ocitocina', 'histerectomia imediata', 'apenas observação', 'curetagem imediata sem avaliar o tônus uterino'], correctIndex: 0, explanation: 'Atonia uterina, causa mais comum de hemorragia pós-parto, é tratada inicialmente com massagem uterina bimanual e ocitocina. Histerectomia imediata é conduta de exceção reservada a casos refratários às medidas iniciais; observação isolada é perigosa diante de hemorragia ativa; curetagem sem avaliar o tônus uterino ignora a causa mais provável (atonia) antes de considerar outras causas.' },
  { id: 'ufrj_gerado26_066', banca: 'UFRJ', cycle: 'Ciclo Ginecologico', subject: 'Ginecologia e Obstetrícia', text: 'Gestante, 32 semanas, hipertensa, com dor abdominal súbita, hipertonia uterina, sangramento escuro, sofrimento fetal agudo. Pode-se afirmar que o diagnóstico e a conduta são:', options: ['descolamento prematuro de placenta; interrupção imediata da gestação', 'placenta prévia; conduta expectante', 'rotura uterina espontânea; observação clínica', 'trabalho de parto normal; acompanhamento sem intervenção'], correctIndex: 0, explanation: 'Dor súbita, hipertonia uterina e sofrimento fetal em gestante hipertensa são clássicos de descolamento prematuro de placenta, exigindo interrupção imediata. Placenta prévia cursa com sangramento indolor sem hipertonia uterina, padrão oposto ao descrito; rotura uterina espontânea é rara sem cicatriz uterina prévia e não seria tratada apenas com observação; trabalho de parto normal não cursa com sofrimento fetal agudo nem hipertonia associada a sangramento.' },
  { id: 'ufrj_gerado26_067', banca: 'UFRJ', cycle: 'Ciclo Ginecologico', subject: 'Ginecologia e Obstetrícia', text: 'Mulher, 55 anos, pós-menopausa, com sangramento vaginal e espessamento endometrial de 13 mm. Pode-se afirmar que a conduta diagnóstica é:', options: ['biópsia endometrial', 'apenas observação clínica', 'histerectomia imediata sem biópsia', 'terapia hormonal isolada'], correctIndex: 0, explanation: 'Sangramento pós-menopausa com espessamento endometrial exige biópsia para excluir hiperplasia atípica ou câncer de endométrio. Observação clínica isolada atrasa o diagnóstico de uma possível neoplasia; histerectomia sem biópsia prévia é conduta desproporcional sem diagnóstico histológico; terapia hormonal isolada não investiga a causa do sangramento nem exclui malignidade.' },
  { id: 'ufrj_gerado26_068', banca: 'UFRJ', cycle: 'Ciclo Ginecologico', subject: 'Ginecologia e Obstetrícia', text: 'Gestante Rh negativo, parceiro Rh positivo, 28 semanas, Coombs indireto negativo. Pode-se afirmar que a conduta profilática é:', options: ['imunoglobulina anti-D profilática', 'nenhuma conduta específica', 'transfusão intrauterina profilática', 'interrupção antecipada da gestação'], correctIndex: 0, explanation: 'Gestante Rh negativo não sensibilizada deve receber imunoglobulina anti-D por volta da 28ª semana para prevenir aloimunização. Não realizar nenhuma conduta expõe a gestante ao risco de sensibilização futura; transfusão intrauterina é tratamento de anemia fetal grave já estabelecida, não profilaxia; interrupção antecipada da gestação não tem indicação nessa situação de rotina sem sensibilização.' },
  { id: 'ufrj_gerado26_069', banca: 'UFRJ', cycle: 'Ciclo Ortopedico', subject: 'Ortopedia', text: 'Homem, 72 anos, com queda da própria altura e encurtamento e rotação externa do membro inferior direito, radiografia confirma fratura do colo femoral deslocada. Pode-se afirmar que a conduta mais adequada é:', options: ['artroplastia do quadril', 'tratamento conservador com repouso prolongado no leito', 'imobilização gessada isolada, sem cirurgia', 'tração cutânea prolongada como tratamento definitivo'], correctIndex: 0, explanation: 'Fratura do colo femoral deslocada em idoso tem indicação de artroplastia, evitando os riscos de repouso prolongado no leito. Tratamento conservador com repouso prolongado aumenta o risco de complicações como tromboembolismo e úlceras de pressão; imobilização gessada isolada não é eficaz para fraturas do colo femoral deslocadas; tração cutânea prolongada não consolida adequadamente esse tipo de fratura, sendo apenas medida temporária.' },
  { id: 'ufrj_gerado26_070', banca: 'UFRJ', cycle: 'Ciclo Ortopedico', subject: 'Ortopedia', text: 'Adolescente, 13 anos, obeso, com dor e claudicação progressiva no quadril esquerdo, radiografia com deslizamento da epífise femoral proximal. Pode-se afirmar que a conduta mais adequada é:', options: ['fixação cirúrgica in situ da epífise', 'tratamento conservador com repouso isolado', 'fisioterapia isolada, sem cirurgia', 'observação clínica até a maturidade esquelética'], correctIndex: 0, explanation: 'O deslizamento da epífise femoral proximal tem tratamento cirúrgico com fixação in situ para evitar progressão e necrose avascular. Repouso isolado não estabiliza a epífise deslizada nem previne a progressão; fisioterapia isolada não substitui a fixação cirúrgica necessária; observar até a maturidade esquelética permite progressão do deslizamento e maior risco de necrose avascular.' },
  { id: 'ufrj_gerado26_071', banca: 'UFRJ', cycle: 'Ciclo Ortopedico', subject: 'Ortopedia', text: 'Homem, 45 anos, com fratura fechada de tíbia imobilizada, evoluindo em 12 horas com dor desproporcional e dor à extensão passiva dos dedos, pulso distal presente. Pode-se afirmar que a conduta imediata é:', options: ['retirada da imobilização e avaliação para fasciotomia de urgência', 'manter a imobilização e reavaliar em 24 horas', 'analgesia potente isolada, sem outra intervenção', 'elevação do membro isolada, sem retirar a imobilização'], correctIndex: 0, explanation: 'Dor desproporcional e dor à extensão passiva são sinais precoces de síndrome compartimental, exigindo retirada da imobilização e avaliação para fasciotomia mesmo com pulso presente. Manter a imobilização e reavaliar em 24 horas atrasa perigosamente o diagnóstico de uma emergência ortopédica; analgesia potente isolada mascara os sintomas sem tratar a causa; elevação isolada sem retirar a imobilização não alivia a pressão compartimental aumentada.' },
  { id: 'ufrj_gerado26_072', banca: 'UFRJ', cycle: 'Ciclo Ortopedico', subject: 'Ortopedia', text: 'Criança de 2 anos, não rastreada previamente, com claudicação e assimetria de pregas cutâneas em membros inferiores, radiografia confirma displasia do desenvolvimento do quadril não tratada. Pode-se afirmar que a conduta é:', options: ['avaliação ortopédica especializada, dado que o tratamento nessa idade tardia frequentemente exige redução cirúrgica', 'apenas observação clínica, sem qualquer intervenção nessa idade', 'uso isolado de suspensório de Pavlik, como em recém-nascidos', 'amputação preventiva do membro'], correctIndex: 0, explanation: 'Diagnóstico tardio de displasia do quadril geralmente exige abordagem ortopédica mais complexa, diferente do suspensório usado em diagnósticos precoces. Observação isolada sem intervenção permite a progressão da displasia não tratada; o suspensório de Pavlik é eficaz principalmente em recém-nascidos, perdendo eficácia em diagnósticos tardios; amputação preventiva não tem qualquer indicação nessa condição ortopédica tratável.' },
  { id: 'ufrj_gerado26_073', banca: 'UFRJ', cycle: 'Ciclo Infectologico', subject: 'Infectologia', text: 'Homem, 35 anos, retorna de área endêmica com febre alta, mialgia intensa, exantema no 4º dia, dor abdominal intensa persistente e sangramento de mucosa. Pode-se afirmar que a classificação de gravidade e a conduta são:', options: ['dengue com sinais de alarme; internação para hidratação venosa e monitorização', 'dengue sem sinais de alarme; alta com hidratação oral apenas', 'febre amarela; vacinação imediata como tratamento', 'zika vírus; apenas sintomáticos e alta'], correctIndex: 0, explanation: 'Dor abdominal intensa e sangramento de mucosa são sinais de alarme na dengue, exigindo internação para hidratação venosa e monitorização. Classificar como dengue sem sinais de alarme ignora justamente os sinais de alarme presentes no caso; vacinação não é tratamento de febre amarela já instalada; zika vírus não costuma cursar com esses sinais de alarme hemorrágicos e abdominais tão intensos.' },
  { id: 'ufrj_gerado26_074', banca: 'UFRJ', cycle: 'Ciclo Infectologico', subject: 'Infectologia', text: 'Homem, 40 anos, com tosse produtiva há 4 semanas, febre vespertina, sudorese noturna, baciloscopia positiva para BAAR. Pode-se afirmar que o esquema terapêutico padrão sem tratamento prévio é:', options: ['RIPE por 2 meses, seguido de rifampicina e isoniazida por 4 meses', 'isoniazida isolada por 6 meses', 'rifampicina isolada por 12 meses', 'etambutol e pirazinamida isolados por 6 meses'], correctIndex: 0, explanation: 'O esquema básico para tuberculose virgem de tratamento é 2 meses de quatro drogas (RIPE) seguidos de 4 meses de rifampicina e isoniazida. Isoniazida isolada por 6 meses é esquema de tratamento de infecção latente, não de doença ativa; rifampicina isolada por 12 meses não segue o esquema padrão preconizado; etambutol e pirazinamida isolados por 6 meses não constituem o esquema básico completo recomendado.' },
  { id: 'ufrj_gerado26_075', banca: 'UFRJ', cycle: 'Ciclo Infectologico', subject: 'Infectologia', text: 'Homem, 45 anos, usuário de drogas injetáveis, com febre prolongada, sopro novo e vegetação em válvula tricúspide. Pode-se afirmar que o conjunto de critérios que confirma o diagnóstico é:', options: ['critérios de Duke modificados', 'critérios de Jones', 'critérios de Framingham', 'critérios de Light'], correctIndex: 0, explanation: 'Os critérios de Duke modificados são usados para confirmar o diagnóstico de endocardite infecciosa, comum em usuários de drogas injetáveis com acometimento tricúspide. Os critérios de Jones são específicos de febre reumática; os de Framingham avaliam risco cardiovascular, não infecção valvar; os de Light classificam derrames pleurais, sem relação com endocardite.' },
  { id: 'ufrj_gerado26_076', banca: 'UFRJ', cycle: 'Ciclo Infectologico', subject: 'Infectologia', text: 'Homem, 45 anos, retorna de viagem a área endêmica de malária com febre cíclica e calafrios, gota espessa confirma Plasmodium falciparum. Pode-se afirmar que a conduta é:', options: ['tratamento antimalárico imediato, atento a sinais de gravidade', 'apenas sintomáticos', 'aguardar sorologia antes de tratar', 'antibiótico de amplo espectro isolado'], correctIndex: 0, explanation: 'Malária por P. falciparum exige tratamento antimalárico imediato, com atenção a sinais de gravidade dado o risco de complicação grave dessa espécie. Sintomáticos isolados não tratam a infecção parasitária confirmada; aguardar sorologia atrasa desnecessariamente o tratamento diante de gota espessa já diagnóstica; antibiótico de amplo espectro não tem ação contra o protozoário Plasmodium.' },
  { id: 'ufrj_gerado26_077', banca: 'UFRJ', cycle: 'Ciclo Infectologico', subject: 'Infectologia', text: 'Homem, 30 anos, HIV positivo, CD4 de 90, com tosse seca e dispneia progressiva, infiltrado intersticial bilateral. Pode-se afirmar que o tratamento de escolha é:', options: ['sulfametoxazol-trimetoprima', 'esquema RIPE isolado', 'betalactâmico isolado', 'quimioterapia isolada'], correctIndex: 0, explanation: 'Pneumonia por Pneumocystis jirovecii em paciente com CD4 baixo é tratada com sulfametoxazol-trimetoprima. Esquema RIPE trata tuberculose, apresentação diferente e não a suspeita principal aqui; betalactâmico isolado não cobre esse fungo atípico; quimioterapia isolada não tem indicação para uma infecção oportunista.' },
  { id: 'ufrj_gerado26_078', banca: 'UFRJ', cycle: 'Ciclo Emergencia', subject: 'Urgência e Emergência', text: 'Homem, 45 anos, trazido ao pronto-socorro após acidente automobilístico, respiração ruidosa e murmúrio vesicular diminuído à direita, PA 85x50 mmHg. Pode-se afirmar que a conduta inicial mais apropriada é:', options: ['avaliação primária ABCDE, com atenção ao tórax e reposição volêmica conforme achados', 'solicitar tomografia de corpo inteiro antes de qualquer intervenção', 'avaliação neurológica isolada antes de avaliar via aérea e respiração', 'alta após analgesia, sem avaliação sistematizada'], correctIndex: 0, explanation: 'O protocolo ATLS exige avaliação sistematizada ABCDE antes de qualquer exame de imagem em paciente politraumatizado instável. Solicitar tomografia antes de estabilizar via aérea e circulação atrasa intervenções salvadoras de vida; avaliar neurologicamente antes de via aérea e respiração inverte a prioridade correta do ABCDE; alta após analgesia é conduta grave e inadequada diante de paciente instável e politraumatizado.' },
  { id: 'ufrj_gerado26_079', banca: 'UFRJ', cycle: 'Ciclo Emergencia', subject: 'Urgência e Emergência', text: 'Paciente em parada cardiorrespiratória com ritmo de fibrilação ventricular confirmado no monitor. Pode-se afirmar que a conduta imediata mais apropriada é:', options: ['desfibrilação precoce assim que disponível', 'aguardar acesso venoso central antes de qualquer choque', 'administrar apenas adrenalina, sem desfibrilação', 'intubação orotraqueal antes de qualquer outra medida, mesmo atrasando o choque'], correctIndex: 0, explanation: 'Em fibrilação ventricular, a desfibrilação precoce é a intervenção mais determinante para sobrevida, devendo ser priorizada sobre qualquer outra medida. Aguardar acesso venoso central atrasa desnecessariamente o choque, que deve ser imediato; adrenalina isolada sem desfibrilação não reverte a fibrilação ventricular; intubação antes do choque atrasa a intervenção mais importante para esse ritmo chocável.' },
  { id: 'ufrj_gerado26_080', banca: 'UFRJ', cycle: 'Ciclo Emergencia', subject: 'Urgência e Emergência', text: 'Paciente com reação anafilática após picada de inseto, edema de face, urticária difusa, dispneia e hipotensão. Pode-se afirmar que a conduta farmacológica imediata mais importante é:', options: ['adrenalina intramuscular imediata', 'anti-histamínico isolado como primeira medida', 'corticoide isolado como primeira medida', 'broncodilatador isolado, sem adrenalina'], correctIndex: 0, explanation: 'A adrenalina intramuscular é a droga de primeira linha na anafilaxia, devendo ser administrada imediatamente, antes de anti-histamínicos ou corticoides. Anti-histamínico isolado não reverte rapidamente a hipotensão e o broncoespasmo da anafilaxia; corticoide isolado tem início de ação lento demais para a emergência anafilática; broncodilatador isolado sem adrenalina não trata o colapso circulatório associado.' },
  { id: 'ufrj_gerado26_081', banca: 'UFRJ', cycle: 'Ciclo Emergencia', subject: 'Urgência e Emergência', text: 'Paciente com rebaixamento do nível de consciência, pupilas puntiformes e frequência respiratória de 6 irpm, história de uso de opioide. Pode-se afirmar que a conduta imediata é:', options: ['suporte ventilatório e administração de naloxona', 'flumazenil isolado, independente da suspeita de opioide', 'apenas observação clínica sem qualquer antídoto', 'lavagem gástrica isolada, sem suporte ventilatório'], correctIndex: 0, explanation: 'A tríade de rebaixamento, miose e bradipneia sugere intoxicação por opioide, tratada com suporte ventilatório e naloxona como antídoto específico. Flumazenil é antídoto de benzodiazepínicos, não de opioides; observação isolada sem antídoto é perigosa diante de bradipneia grave; lavagem gástrica isolada não reverte a depressão respiratória aguda que exige suporte ventilatório imediato.' },
  { id: 'ufrj_gerado26_082', banca: 'UFRJ', cycle: 'Ciclo Emergencia', subject: 'Urgência e Emergência', text: 'Paciente com dor torácica em repouso, curta duração, ECG mostrando infradesnivelamento transitório do segmento ST durante os episódios e troponina discretamente elevada. Pode-se afirmar que a classificação e a conduta inicial são:', options: ['infarto sem supradesnivelamento do ST; dupla antiagregação e estratificação invasiva conforme risco', 'angina estável; apenas ajuste de medicação oral ambulatorial', 'infarto com supradesnivelamento do ST; trombólise imediata', 'pericardite aguda; anti-inflamatório isolado'], correctIndex: 0, explanation: 'Dor recorrente com alteração dinâmica do ST e troponina elevada caracteriza infarto sem supra de ST, tratado com dupla antiagregação e estratificação invasiva. Angina estável não cursaria com troponina elevada; não há supradesnivelamento do ST descrito, afastando a indicação de trombólise; pericardite aguda cursaria com supra difuso côncavo e não com infradesnivelamento transitório associado a troponina elevada.' },
  { id: 'ufrj_gerado26_083', banca: 'UFRJ', cycle: 'Ciclo Psiquiatrico', subject: 'Psiquiatria', text: 'Homem, 30 anos, com pensamentos intrusivos recorrentes sobre contaminação e rituais de lavagem das mãos por horas ao dia, reconhecendo o comportamento como excessivo. Pode-se afirmar que a classe medicamentosa de primeira linha é:', options: ['inibidor seletivo da recaptação de serotonina em doses geralmente mais altas que na depressão', 'antipsicótico isolado', 'benzodiazepínico isolado como tratamento de manutenção', 'psicanálise isolada, sem medicação'], correctIndex: 0, explanation: 'No transtorno obsessivo-compulsivo, os ISRS são a primeira linha farmacológica, geralmente em doses mais altas do que as usadas na depressão. Antipsicótico isolado não é primeira linha nesse transtorno; benzodiazepínico isolado não trata o núcleo obsessivo-compulsivo e traz risco de dependência em uso contínuo; psicanálise isolada sem medicação não é a abordagem farmacológica de primeira linha recomendada.' },
  { id: 'ufrj_gerado26_084', banca: 'UFRJ', cycle: 'Ciclo Psiquiatrico', subject: 'Psiquiatria', text: 'Mulher, 25 anos, com episódios de humor exaltado, redução da necessidade de sono e grandiosidade, intercalados com períodos de humor deprimido. Pode-se afirmar que a classe medicamentosa de escolha para o episódio agudo maníaco é:', options: ['estabilizador de humor', 'apenas psicoterapia, sem medicação', 'antidepressivo isolado', 'antipsicótico isolado, sem estabilizador de humor'], correctIndex: 0, explanation: 'No transtorno bipolar, o estabilizador de humor é a classe de escolha para tratar o episódio maníaco agudo. Psicoterapia isolada sem medicação não controla um episódio maníaco agudo; antidepressivo isolado pode precipitar viragem maníaca em transtorno bipolar; antipsicótico isolado sem estabilizador de humor não é a estratégia padrão recomendada para manutenção do quadro.' },
  { id: 'ufrj_gerado26_085', banca: 'UFRJ', cycle: 'Ciclo Psiquiatrico', subject: 'Psiquiatria', text: 'Paciente em uso de antipsicótico apresenta rigidez muscular importante, hipertermia, alteração do nível de consciência e CPK muito elevada. Pode-se afirmar que a conduta imediata é:', options: ['suspensão do antipsicótico e suporte intensivo', 'apenas suspensão de ISRS, sem relação com antipsicótico', 'benzodiazepínico isolado, sem suspender o antipsicótico', 'anticonvulsivante isolado'], correctIndex: 0, explanation: 'Esse quadro caracteriza síndrome neuroléptica maligna, exigindo suspensão imediata do antipsicótico e suporte intensivo. Suspender apenas ISRS ignora o verdadeiro agente causador (o antipsicótico); benzodiazepínico isolado sem suspender o antipsicótico não remove a causa da síndrome; anticonvulsivante isolado não trata a hipertermia nem a rigidez muscular da síndrome neuroléptica maligna.' },
  { id: 'ufrj_gerado26_086', banca: 'UFRJ', cycle: 'Ciclo Psiquiatrico', subject: 'Psiquiatria', text: 'Homem, 40 anos, com humor deprimido, anedonia, insônia e ideação suicida estruturada com plano definido há 3 semanas. Pode-se afirmar que a conduta imediata mais apropriada é:', options: ['avaliação de risco de suicídio e encaminhamento para internação ou acompanhamento intensivo conforme gravidade', 'alta com antidepressivo oral e retorno ambulatorial em 30 dias', 'apenas orientação de psicoterapia sem qualquer avaliação de risco imediato', 'observação domiciliar pela família, sem avaliação médica adicional'], correctIndex: 0, explanation: 'Ideação suicida estruturada com plano definido exige avaliação de risco imediata e possível internação, não podendo aguardar retorno ambulatorial tardio. Alta com retorno em 30 dias é perigosa diante de risco iminente de suicídio; orientação de psicoterapia sem avaliação de risco ignora a gravidade do plano suicida estruturado; observação domiciliar pela família não substitui a avaliação médica especializada urgente necessária.' },
  { id: 'ufrj_gerado26_087', banca: 'UFRJ', cycle: 'Ciclo Psiquiatrico', subject: 'Psiquiatria', text: 'Paciente idoso apresenta episódios recorrentes de confusão mental de início agudo e flutuante, associados a infecção urinária, com retorno ao basal cognitivo após tratamento do quadro infeccioso. Pode-se afirmar que o diagnóstico mais provável é:', options: ['delirium precipitado por infecção urinária', 'demência de Alzheimer em fase inicial', 'depressão maior com sintomas cognitivos', 'demência vascular estabelecida'], correctIndex: 0, explanation: 'Confusão de início agudo e flutuante, com retorno ao basal após tratamento da causa, é característica do delirium, diferente das demências, que são progressivas e permanentes. Alzheimer inicial não teria esse padrão de resolução completa após tratar a infecção; depressão maior não causa flutuação aguda de consciência desse tipo; demência vascular estabelecida também não retornaria ao basal cognitivo simplesmente com o tratamento da infecção urinária.' },
  { id: 'ufrj_gerado26_088', banca: 'UFRJ', cycle: 'Ciclo Etica', subject: 'Ética Médica', text: 'Paciente adulto, lúcido e orientado, recusa transfusão sanguínea por motivos religiosos mesmo diante de risco de vida documentado. Pode-se afirmar que o princípio bioético que deve prevalecer na conduta médica é:', options: ['respeito à autonomia do paciente, desde que devidamente informado e capaz', 'beneficência isolada, ignorando a vontade do paciente capaz', 'transfusão à revelia, por decisão unilateral da equipe médica', 'transferência de responsabilidade para familiares'], correctIndex: 0, explanation: 'Paciente adulto e capaz tem direito a recusar tratamento, prevalecendo o princípio da autonomia mesmo diante de risco de vida. Beneficência isolada que ignora a vontade do paciente capaz desrespeita sua autonomia; transfusão à revelia viola o direito do paciente a decidir sobre seu próprio corpo; transferir a decisão para familiares ignora que o próprio paciente capaz é quem detém o direito de decidir.' },
  { id: 'ufrj_gerado26_089', banca: 'UFRJ', cycle: 'Ciclo Etica', subject: 'Ética Médica', text: 'Médico é procurado pela polícia solicitando informações do prontuário de um paciente para investigação criminal, sem autorização judicial nem consentimento do paciente. Pode-se afirmar que a conduta ética apropriada é:', options: ['recusar a quebra de sigilo sem autorização judicial ou consentimento, salvo exceções legais específicas', 'fornecer todas as informações imediatamente, por se tratar de autoridade policial', 'fornecer apenas informações administrativas, sem qualquer critério ético', 'destruir o prontuário para evitar qualquer questionamento futuro'], correctIndex: 0, explanation: 'O sigilo médico deve ser mantido salvo exceções legais específicas, não bastando solicitação policial isolada sem base legal formal. Fornecer todas as informações apenas por se tratar de autoridade policial ignora a exigência de base legal para quebra de sigilo; fornecer informações "administrativas" sem critério ético claro ainda representa quebra indevida de sigilo; destruir o prontuário constitui infração ética grave e ilegal, além de prejudicar o próprio paciente.' },
  { id: 'ufrj_gerado26_090', banca: 'UFRJ', cycle: 'Ciclo Etica', subject: 'Ética Médica', text: 'Paciente terminal, lúcido, formaliza documento expressando quais tratamentos deseja ou não receber caso venha a perder a capacidade de decisão futuramente. Pode-se afirmar que esse instrumento é:', options: ['diretivas antecipadas de vontade (testamento vital)', 'termo de consentimento livre e esclarecido padrão, sem validade futura', 'procuração jurídica sem relação com decisões de saúde', 'termo de responsabilidade por alta a pedido'], correctIndex: 0, explanation: 'As diretivas antecipadas de vontade permitem que o paciente registre suas preferências para tratamentos futuros, a serem respeitadas caso perca a capacidade de decisão. O termo de consentimento padrão vale para um procedimento específico no presente, sem essa validade prospectiva; procuração jurídica trata de questões patrimoniais/civis, não de decisões de saúde; termo de responsabilidade por alta a pedido é documento distinto, usado quando o paciente deixa o hospital contra orientação médica.' },
  { id: 'ufrj_gerado26_091', banca: 'UFRJ', cycle: 'Ciclo Etica', subject: 'Ética Médica', text: 'Médico comete erro de prescrição que causa dano ao paciente, por desatenção a alergia registrada em prontuário. Pode-se afirmar que a natureza da responsabilidade médica nesse cenário é:', options: ['responsabilidade subjetiva, exigindo comprovação de culpa (negligência, imprudência ou imperícia)', 'responsabilidade objetiva, independente de culpa', 'nenhuma responsabilidade, pois erros de prescrição são sempre escusáveis', 'responsabilidade exclusivamente institucional, sem qualquer responsabilidade pessoal do médico'], correctIndex: 0, explanation: 'A responsabilidade civil médica é, em regra, subjetiva, exigindo comprovação de culpa para configurar erro médico indenizável. Responsabilidade objetiva independeria de culpa, o que não é a regra geral aplicada à conduta médica pessoal; afirmar que não há responsabilidade alguma ignora que a desatenção a um dado registrado configura negligência; atribuir a responsabilidade exclusivamente à instituição ignora a responsabilidade pessoal do profissional que cometeu o erro.' },
  { id: 'ufrj_gerado26_092', banca: 'UFRJ', cycle: 'Ciclo Geriatrico', subject: 'Geriatria', text: 'Mulher, 82 anos, com perda de peso não intencional, fadiga, velocidade de marcha reduzida e força de preensão palmar diminuída, baixa atividade física referida. Pode-se afirmar que o diagnóstico mais provável e a abordagem terapêutica principal são:', options: ['síndrome de fragilidade; exercício físico resistido e suporte nutricional', 'depressão maior; antidepressivo isolado, sem abordagem funcional', 'demência em fase inicial; anticolinesterásico isolado', 'hipotireoidismo subclínico; reposição hormonal isolada'], correctIndex: 0, explanation: 'Perda de peso, fadiga, marcha lentificada e força reduzida compõem o fenótipo da síndrome de fragilidade, tratada com exercício resistido e suporte nutricional. Depressão maior não é definida por esses critérios físicos objetivos de fragilidade; demência em fase inicial teria comprometimento cognitivo como achado central, não descrito no caso; hipotireoidismo subclínico não define esse fenótipo físico característico de fragilidade.' },
  { id: 'ufrj_gerado26_093', banca: 'UFRJ', cycle: 'Ciclo Geriatrico', subject: 'Geriatria', text: 'Homem, 78 anos, em uso de múltiplas medicações prescritas por diferentes especialistas, internado por confusão mental e quedas de repetição. Pode-se afirmar que a conduta inicial mais apropriada é:', options: ['revisão completa da lista de medicamentos, buscando desprescrição de fármacos inadequados para idosos', 'adicionar mais um medicamento sedativo para controlar a agitação', 'manter todas as prescrições inalteradas, focando apenas em exames de imagem', 'aumentar empiricamente a dose de todos os medicamentos em uso'], correctIndex: 0, explanation: 'Polifarmácia é causa comum e reversível de confusão e quedas em idosos, exigindo revisão e desprescrição de medicamentos inadequados. Adicionar mais um sedativo agravaria o problema de polifarmácia já existente; manter tudo inalterado ignora a causa medicamentosa reversível mais provável; aumentar empiricamente as doses pioraria ainda mais o risco de efeitos adversos cumulativos.' },
  { id: 'ufrj_gerado26_094', banca: 'UFRJ', cycle: 'Ciclo Geriatrico', subject: 'Geriatria', text: 'Mulher, 75 anos, é avaliada quanto a mobilidade, cognição, humor, capacidade funcional e uso de medicações, de forma estruturada e multiprofissional. Pode-se afirmar que esse instrumento é:', options: ['avaliação geriátrica ampla (multidimensional)', 'escala de coma de Glasgow isolada', 'mini exame do estado mental isolado', 'escore de Apgar adaptado'], correctIndex: 0, explanation: 'A avaliação geriátrica ampla é a abordagem multidimensional estruturada que investiga múltiplos domínios do idoso, orientando o plano de cuidado. A escala de coma de Glasgow avalia apenas nível de consciência em contexto agudo, não múltiplos domínios geriátricos; o mini exame do estado mental avalia isoladamente a cognição, sendo apenas parte da avaliação ampla; o escore de Apgar é usado em recém-nascidos, sem qualquer aplicação geriátrica.' },
  { id: 'ufrj_gerado26_095', banca: 'UFRJ', cycle: 'Ciclo SaudeColetiva', subject: 'Saúde Coletiva', text: 'Médico da atenção básica diagnostica caso confirmado de sarampo em criança de 3 anos. Pode-se afirmar que a conduta obrigatória em relação à vigilância epidemiológica é:', options: ['notificação compulsória imediata às autoridades de saúde', 'notificação apenas se houver óbito associado ao caso', 'não há necessidade de notificação, apenas tratamento clínico', 'notificação mensal consolidada, sem urgência'], correctIndex: 0, explanation: 'Sarampo é doença de notificação compulsória imediata, dado seu potencial de gerar surtos. Notificar apenas em caso de óbito ignora a exigência de notificação diante de qualquer caso confirmado; não notificar viola a legislação sanitária vigente; notificação mensal consolidada é incompatível com a urgência exigida por uma doença de alto potencial epidêmico como o sarampo.' },
  { id: 'ufrj_gerado26_096', banca: 'UFRJ', cycle: 'Ciclo SaudeColetiva', subject: 'Saúde Coletiva', text: 'Estudo de coorte acompanha expostos e não expostos a determinado fator ao longo de 10 anos, comparando a incidência da doença entre os dois grupos por meio de uma razão. Pode-se afirmar que essa medida de associação é:', options: ['risco relativo', 'razão de chances (odds ratio)', 'prevalência', 'mortalidade proporcional'], correctIndex: 0, explanation: 'O risco relativo é a razão entre a incidência da doença nos expostos e nos não expostos, medida de associação característica de estudos de coorte. A razão de chances (odds ratio) é a medida típica de estudos caso-controle, não de coorte; prevalência mede a proporção de casos existentes em um momento, não uma razão entre incidências; mortalidade proporcional mede a distribuição de óbitos por causa, sem relação com esse desenho de estudo.' },
  { id: 'ufrj_gerado26_097', banca: 'UFRJ', cycle: 'Ciclo SaudeColetiva', subject: 'Saúde Coletiva', text: 'Criança apresenta febre alta e exantema 8 dias após receber a vacina tríplice viral, sem outra causa identificada. Pode-se afirmar que a conduta correta em relação a esse evento é:', options: ['notificar como evento adverso pós-vacinação (EAPV) para investigação, sem que isso implique contraindicação automática a doses futuras', 'omitir o caso, pois reações após vacina não devem ser notificadas', 'contraindicar definitivamente qualquer vacina futura para essa criança', 'suspender a vacinação de toda a comunidade até nova ordem'], correctIndex: 0, explanation: 'Eventos adversos pós-vacinação devem ser notificados para investigação e vigilância, sem que isso signifique automaticamente contraindicação a doses futuras, que depende da avaliação do nexo causal. Omitir o caso viola o dever de notificação da vigilância de eventos adversos; contraindicar definitivamente sem avaliação do nexo causal é conduta precipitada; suspender a vacinação de toda a comunidade por um caso isolado é desproporcional e não segue os protocolos de vigilância.' },
  { id: 'ufrj_gerado26_098', banca: 'UFRJ', cycle: 'Ciclo Intensivo', subject: 'Medicina Intensiva', text: 'Paciente crítico em sepse grave evolui com hipoxemia refratária, infiltrado bilateral difuso, relação PaO2/FiO2 de 110. Pode-se afirmar que a estratégia ventilatória protetora indicada é:', options: ['baixo volume corrente (cerca de 6 mL/kg de peso predito)', 'volume corrente elevado para melhor troca gasosa', 'ventilação espontânea isolada', 'extubação precoce independente da gasometria'], correctIndex: 0, explanation: 'Na SARA moderada, a ventilação protetora com baixo volume corrente reduz a lesão pulmonar induzida pela ventilação mecânica. Volume corrente elevado aumenta o risco de barotrauma e piora a lesão pulmonar na SARA; ventilação espontânea isolada é insuficiente diante de hipoxemia refratária grave; extubação precoce independente da gasometria é perigosa diante de troca gasosa ainda comprometida.' },
  { id: 'ufrj_gerado26_099', banca: 'UFRJ', cycle: 'Ciclo Intensivo', subject: 'Medicina Intensiva', text: 'Paciente com foco pulmonar, PA 85x50 mmHg, confuso, lactato elevado após 30 mL/kg de cristaloide. Pode-se afirmar que a próxima conduta é:', options: ['iniciar noradrenalina', 'repetir apenas cristaloide indefinidamente', 'corticoide em altas doses isolado', 'transfusão independente da hemoglobina'], correctIndex: 0, explanation: 'Choque séptico refratário à reposição volêmica inicial indica início de vasopressor, sendo a noradrenalina a primeira escolha. Repetir cristaloide indefinidamente sem resposta expõe a paciente a sobrecarga volêmica sem benefício adicional; corticoide isolado em altas doses não é a próxima conduta padrão diante de choque refratário; transfusão independente da hemoglobina não tem indicação sem critério transfusional estabelecido.' },
  { id: 'ufrj_gerado26_100', banca: 'UFRJ', cycle: 'Ciclo Intensivo', subject: 'Medicina Intensiva', text: 'Paciente em choque cardiogênico refratário a inotrópicos após infarto extenso, aguardando definição de estratégia de revascularização. Pode-se afirmar que o dispositivo de suporte circulatório temporário a ser considerado como ponte terapêutica é:', options: ['balão intra-aórtico ou dispositivo de assistência circulatória de curta duração', 'marca-passo definitivo isolado, sem suporte circulatório', 'apenas aumento da dose de vasopressor, sem dispositivo mecânico', 'cardioversão elétrica isolada, sem suporte circulatório'], correctIndex: 0, explanation: 'No choque cardiogênico refratário, dispositivos de suporte circulatório mecânico temporário servem de ponte até a definição terapêutica definitiva. Marca-passo definitivo isolado não trata a disfunção contrátil do choque cardiogênico; aumentar apenas a dose de vasopressor sem suporte mecânico já se mostrou insuficiente (choque refratário a inotrópicos); cardioversão elétrica isolada é indicada para arritmias específicas, não para o choque cardiogênico refratário em si.' },
];
